document.addEventListener("DOMContentLoaded",()=>{const e=["“Real estate is more than an investment — it’s the backdrop of your best moments.”","“Every home has a story. My job is to help you find the one that transforms your life.”","“From dream to doorstep, I’m with you every step of the way.”"],t=document.getElementById("story-quote");let s=0;t.classList.add("active"),setInterval(()=>{t.classList.remove("active"),t.classList.add("slide-out"),setTimeout(()=>{s=(s+1)%e.length,t.textContent=e[s],t.classList.remove("slide-out"),t.classList.add("slide-in"),setTimeout(()=>{t.classList.remove("slide-in"),t.classList.add("active")},100)},800)},5e3)});